solution: class Solution {
    public String solveEquation(String equation) {
        String[] parts = equation.split("=");
        int[] left = evaluate(parts[0]);
        int[] right = evaluate(parts[1]);
        int a = left[0] - right[0];
        int b = right[1] - left[1];
        if (a == 0) {
            return b == 0 ? "Infinite solutions" : "No solution";
        }
        return "x=" + (b / a);
    }

    private int[] evaluate(String expr) {
        int a = 0, b = 0, sign = 1, n = expr.length();
        for (int i = 0; i < n; ) {
            char c = expr.charAt(i);
            if (c == '+' || c == '-') {
                sign = c == '+' ? 1 : -1;
                i++;
                continue;
            }
            int num = 0;
            boolean hasNum = false;
            while (i < n && Character.isDigit(expr.charAt(i))) {
                num = num * 10 + (expr.charAt(i) - '0');
                hasNum = true;
                i++;
            }
            if (i < n && expr.charAt(i) == 'x') {
                a += sign * (hasNum ? num : 1);
                i++;
            } else {
                b += sign * (hasNum ? num : 0);
            }
        }
        return new int[]{a, b};
    }
}
